def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        decay_factor = 1.0
        complexity_penalty = 0.0
        synergy_bonus = 1.0
        residual_factor = 1.0
        for stage in range(1, 15):
            if stage % 4 == 0 and cap % (stage + 2) == 0:
                decay_factor *= 0.92 + 0.007 * stage
            elif stage % 6 == 0 and int(ratio * 100) % (stage + 3) != 0:
                decay_factor *= 1.03 - 0.008 * stage
            if ratio < (pow(0.1, 1/stage)):
                base_score += (np.exp(-ratio*stage) + np.sin(stage)) * decay_factor
            else:
                base_score += np.log1p(stage*item) / (stage + 1) * decay_factor
            if (cap + stage*3) % 11 == 0:
                base_score *= 1.07
            elif (cap * stage) % 9 == 0:
                base_score *= 0.93
            if stage == 5:
                for substage in range(1, 8):
                    delta = cap - item * substage * substage
                    if delta > 0:
                        complexity_penalty += (np.tanh(delta/(substage+1)) * substage) / (substage + 4)
                    else:
                        complexity_penalty -= abs(delta)**1.2 / (substage + 3)
            if ratio > 0.7 and stage % 3 == 0:
                synergy_bonus *= 1.2 + 0.015 * stage
            elif ratio < 0.15 and stage % 5 == 0:
                synergy_bonus *= 0.85 - 0.02 * stage
            if stage % 7 == 0 and (cap + stage) % 5 == 0:
                complexity_penalty += np.cos(ratio * stage) * 0.4
            if stage % 2 == 1:
                residual_factor *= 1.01 + 0.005 * np.sin(stage * ratio * np.pi)
            else:
                residual_factor *= 0.99 - 0.004 * np.cos(stage + ratio)
        total_score = (base_score + complexity_penalty * 0.9) * synergy_bonus * residual_factor
        if total_score <= 0:
            priorities[i] = -total_score * (1 + np.sqrt(cap/item)) / (1 + np.log1p(cap))
        else:
            if cap > item * 5:
                priorities[i] = -total_score / (np.cbrt(cap) + 2) * (1 + ratio**2)
            else:
                priorities[i] = -total_score / (cap + 5) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[i] *= 1.22
            if cap % 3 == 0:
                priorities[i] *= 1.05
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 2 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.03
    return priorities
